import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import matplotlib.patches as patches; fig, ax = plt.subplots(figsize=(5, 4)); B = (1, 1); A = (1, 4); C = (5, 1); triangle = patches.Polygon([A, B, C], closed=True, fill=False, edgecolor='#1a1a1a', linewidth=2); ax.add_patch(triangle); right_angle = patches.Polygon([(1, 1.3), (1.3, 1.3), (1.3, 1)], closed=False, fill=False, edgecolor='#1a1a1a', linewidth=1); ax.add_patch(right_angle); ax.text(0.9, 4.1, 'A', fontsize=12, ha='right', va='bottom'); ax.text(0.8, 0.8, 'B', fontsize=12, ha='right', va='top'); ax.text(5.2, 0.8, 'C', fontsize=12, ha='left', va='top'); ax.text(3.2, 2.7, '10 cm', fontsize=12, ha='left', va='bottom'); ax.set_xlim(0, 6); ax.set_ylim(0, 5); ax.set_aspect('equal'); ax.axis('off'); plt.savefig('out.png', dpi=150, bbox_inches='tight')